+  agents.forEach(agent => {
+    agent.tick = (agent.tick || 0) + 1;
+    if (!agent.animState) {
+      agent.animState = { direction: 'down', walkFrame: 0 };
+    }
+    updateMovement(agent, agent.tick, agent.animState);
+    drawCharacter(ctx, agent, agent.animState);
+  });
+}
+
+interface Position {
+  x: number;
+  y: number;
+  width: number;
+  height: number;
+}
+
+function drawTooltip(ctx: CanvasRenderingContext2D, x: number, y: number, agent: AgentInfo, tokenBudgetUsed: number) {
+  const padding = 8;
+  const lineHeight = 16;
+  const lines = [
+    `${agent.name} (${agent.tier})`,
+    `Status: ${agent.state}`,
+    `Task: ${agent.currentJob ?? 'None'}`,
+    `Tokens: ${tokenBudgetUsed}`,
+  ];
+
+  // Measure max text width
+  ctx.font = '14px "Press Start 2P", monospace';
+  let maxWidth = 0;
+  for (const line of lines) {
+    const w = ctx.measureText(line).width;
+    if (w > maxWidth) maxWidth = w;
+  }
+  const width = maxWidth + padding * 2;
+  const height = lineHeight * lines.length + padding * 2;
+
+  // Clamp tooltip position inside canvas
+  const canvas = ctx.canvas;
+  let tx = x + 12;
+  let ty = y + 12;
+  if (tx + width > canvas.width) tx = x - width - 12;
+  if (ty + height > canvas.height) ty = y - height - 12;
+
+  // Draw background panel with pixel-art style
+  ctx.fillStyle = '#1a1a2e';
+  ctx.strokeStyle = '#d4af37'; // gold border
+  ctx.lineWidth = 2;
+  ctx.shadowColor = 'rgba(0,0,0,0.8)';
+  ctx.shadowBlur = 4;
+  ctx.shadowOffsetX = 2;
+  ctx.shadowOffsetY = 2;
+  ctx.fillRect(tx, ty, width, height);
+  ctx.strokeRect(tx + 1, ty + 1, width - 2, height - 2);
+  ctx.shadowBlur = 0;
+  ctx.shadowOffsetX = 0;
+  ctx.shadowOffsetY = 0;
+
+  // Draw text in parchment color
+  ctx.fillStyle = '#f5deb3'; // wheat/parchment color
+  ctx.textBaseline = 'top';
+  for (let i = 0; i < lines.length; i++) {
+    ctx.fillText(lines[i], tx + padding, ty + padding + i * lineHeight);
+  }
+}
+
+export function AgentsScene() {
+  const canvasRef = useRef<HTMLCanvasElement>(null);
+  const [agents, setAgents] = useState<AgentInfo[]>(DEFAULT_AGENTS);
+  const [hoverAgent, setHoverAgent] = useState<AgentInfo | null>(null);
+  const [hoverPos, setHoverPos] = useState<{ x: number; y: number } | null>(null);
+
+  // Map of agent id to position rectangle for hit testing
+  const agentPositions = useRef<Map<string, Position>>(new Map());
+
+  // Poll agents every 5 seconds
+  useEffect(() => {
+    let active = true;
+    const poll = () => {
+      fetch('/api/agents')
+        .then((r) => r.ok ? r.json() : [])
+        .then((data: AgentInfo[]) => {
+          if (active && Array.isArray(data) && data.length > 0) setAgents(data);
+        })
+        .catch(() => {});
+    };
+    poll();
+    const iv = setInterval(poll, 5000);
+    return () => {
+      active = false;
+      clearInterval(iv);
+    };
+  }, []);
+
+  useEffect(() => {
+    if (!canvasRef.current) return;
+
+    const canvas = canvasRef.current;
+    const ctx = canvas.getContext('2d');
+    if (!ctx) return;
+
+    const cancel = startGameLoop((dt, frameCount) => {
+      const rc = syncCanvasSize(canvas);
+      clearCanvas(rc);
+
+      const cols = 3;
+      const padding = 10;
+      const labelH = 24;
+      const roomW = Math.floor((rc.width - padding * (cols + 1)) / cols);
+      const roomH = Math.min(Math.floor(roomW * 0.7), 180);
+
+      // Group agents by tier
+      const agentsByTier = new Map<string, AgentInfo[]>();
+      for (const a of agents) {
+        const list = agentsByTier.get(a.tier) ?? [];
+        list.push(a);
+        agentsByTier.set(a.tier, list);
+      }
+
+      // Clear previous positions
+      agentPositions.current.clear();
+
+      for (const slot of ROOM_GRID) {
+        const rx = padding + slot.col * (roomW + padding);
+        const ry = padding + slot.row * (roomH + labelH + padding + 6);
+
+        // Room label with shadow
+        drawText(rc, slot.label.toUpperCase(), rx + 5, ry + 15, 11, '#000000');
+        drawText(rc, slot.label.toUpperCase(), rx + 4, ry + 14, 11, COLORS.gold);
+
+        // Room background
+        drawRoom(rc.ctx, slot.tier, rx, ry + labelH, roomW, roomH, frameCount);
+
+        // Room border (double line for depth)
+        rc.ctx.strokeStyle = '#2a2030';
+        rc.ctx.lineWidth = 2;
+        rc.ctx.strokeRect(rx, ry + labelH, roomW, roomH);
+        rc.ctx.strokeStyle = '#5a5a6a';
+        rc.ctx.lineWidth = 1;
+        rc.ctx.strokeRect(rx + 1, ry + labelH + 1, roomW - 2, roomH - 2);
+
+        // Draw agents in this room (cap visible at 4, show overflow badge)
+        const tierAgents = agentsByTier.get(slot.tier) ?? [];
+        const maxVisible = 4;
+        const visible = tierAgents.slice(0, maxVisible);
+        const overflow = tierAgents.length - visible.length;
+        const charScale = Math.min(2.5, roomW / 90);
+
+        visible.forEach((agent, i) => {
+          // Determine target position based on agent state
+          let targetX: number;
+          let targetY: number;
+
+          if (agent.state === 'running') {
+            // Position at workstation furniture
+            const wsPos = getWorkstationPosition(slot.tier);
+            targetX = rx + roomW * wsPos.x;
+            targetY = ry + labelH + roomH * wsPos.y;
+          } else {
+            // Idle: random spread within walkable area
+            const spreadX = roomW * 0.7;
+            const spreadY = roomH * 0.45;
+            targetX = rx + roomW * 0.15 + i * Math.min(55, spreadX / Math.max(1, visible.length));
+            targetY = ry + labelH + roomH * 0.45;
+          }
+
+          // Get current character state and smoothly update position
+          const cs = getCS(agent.id, targetX, targetY);
+
+          // Smoothly update position towards target
+          const updatedPos = updateCharacterPosition(agent.id, cs.x, cs.y, targetX, targetY, dt);
+          cs.x = updatedPos.x;
+          cs.y = updatedPos.y;
+
+          // Draw character with updated position and pass state
+          drawCharacter(
+            rc.ctx,
+            slot.tier as CharacterType,
+            agent.state as AnimState,
+            cs.x,
+            cs.y,
+            charScale,
+            frameCount,
+            agent.id,
+            agent.currentJob,
+          );
+
+          // Name plate (below character)
+          const nameY = cs.y + 24 * charScale;
+          drawText(rc, agent.name, cs.x - 4, nameY, 9, COLORS.text);
+
+          // Store position for hit testing (approximate bounding box)
+          const width = 32 * charScale;
+          const height = 32 * charScale;
+          agentPositions.current.set(agent.id, {
+            x: cs.x - width / 2,
+            y: cs.y - height / 2,
+            width,
+            height,
+          });
+        });
+      }
+
+      // Draw tooltip if hovering over an agent
+      if (hoverAgent && hoverPos) {
+        // For demo, token budget used is fixed or could be agent id length * 100 as dummy
+        const tokenBudgetUsed = 1234;
+        drawTooltip(rc.ctx, hoverPos.x, hoverPos.y, hoverAgent, tokenBudgetUsed);
+      }
+    });
+
+    return () => cancel();
+  }, [agents, hoverAgent, hoverPos]);
+
+  // Mouse move handler for hit testing
+  function handleMouseMove(e: React.MouseEvent<HTMLCanvasElement>) {
+    const canvas = canvasRef.current;
+    if (!canvas) return;
+    const rect = canvas.getBoundingClientRect();
+    const x = e.clientX - rect.left;
+    const y = e.clientY - rect.top;
+
+    // Hit test agents
+    let foundAgent: AgentInfo | null = null;
+    for (const agent of agents) {
+      const pos = agentPositions.current.get(agent.id);
+      if (pos) {
+        if (x >= pos.x && x <= pos.x + pos.width && y >= pos.y && y <= pos.y + pos.height) {
+          foundAgent = agent;
+          break;
+        }
+      }
+    }
+    setHoverAgent(foundAgent);
+    setHoverPos(foundAgent ? { x, y } : null);
+  }
+
+  return (
+    <canvas
+      ref={canvasRef}
+      width={800}
+      height={600}
+      style={{ width: '100%', height: '100%', imageRendering: 'pixelated', cursor: hoverAgent ? 'pointer' : 'default' }}
+      onMouseMove={handleMouseMove}
+      onMouseLeave={() => { setHoverAgent(null); setHoverPos(null); }}
+    />
+  );
 }
